  ('elementary-7c4986e7-moex-00030', 'elementary-7c4986e7', 'elementary-7c4986e7-moex-110-862adcfa', 'sub-elementary-7c4986e7-01', NULL, 'single_choice', '假設有一批貨物投保海上保險並採取優先賠償制（primarycoveragebasis），該批貨物原產地之保險價額 為200萬，保險單A承保生效日期較早，保額為150萬；保險單B承保生效日期較晚，保額為100萬。 若兩張保險單皆生效後發生海難，貨物損失金額為200萬，則保險單A與B各應分擔多少賠款？', '["保險單A為100萬，保險單B為100萬", "保險單A為120萬，保險單B為80萬", "保險單A為150萬，保險單B為50萬", "保險單A為200萬，保險單B為0元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "469a90b16e7f", "answer_pdf_sha1": "2a8efabd8071", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "508", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "保險學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "金融保險"}'::jsonb, NULL),
